/* STRICT VALIDATION */
const item = $input.first()?.json || {};
const data = item.data || item.body?.data || item.body || item;

const chat_id = data.chat_id;
const text = data.text || data.ai_response;

const isValid = !!(chat_id && text && text.length > 2);

if (!isValid) {
  return [{
    json: {
      success: false,
      isValid: false,
      error_code: "VALIDATION_ERROR",
      error_message: "Payload missing required fields for AI Agent",
      _meta: { source: "NN_03_AI_Agent", timestamp: new Date().toISOString() }
    }
  }];
}

return [{
  json: {
    isValid: true,
    chat_id,
    text,
    availability: item.availability || {},
    original_data: data
  }
}];

const input = $input.first().json;
const avail = input.availability || {};
const systemPrompt = `Eres un asistente para Booking Titanium. REGLA DE ORO: Si el usuario pide una fecha y en el CONTEXTO DE DISPONIBILIDAD sale que no hay o hay otros días, sugiere proactivamente los slots disponibles que te pasamos. CONTEXTO DISPONIBILIDAD: ${JSON.stringify(avail)}`;

return [{
  json: {
    payload: {
      model: "llama-3.3-70b-versatile",
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: input.text }
      ]
    }
  }
}];

const res = $input.first()?.json || {};
let ai_data = {};
try { 
  const content = res.choices ? res.choices[0].message.content : (res.response || JSON.stringify(res));
  try {
    ai_data = JSON.parse(content); 
  } catch(e) {
    ai_data = { response: content };
  }
} catch(e) { 
  ai_data = { response: "Lo siento, hubo un error procesando tu solicitud de IA." }; 
}

const pre = $node["Extract & Validate (PRE)"]?.json || {};
return [{
  json: {
    success: true,
    data: {
      intent: ai_data.intent || "CREATE",
      chat_id: pre.chat_id || "unknown",
      user_email: ai_data.email,
      booking_id: ai_data.booking_id,
      start_time: (ai_data.date && ai_data.time) ? (ai_data.date + "T" + ai_data.time + ":00Z") : null,
      ai_response: ai_data.response || ai_data.content || "IA procesó la solicitud."
    }
  }
}];

return [{
  json: {
    success: false,
    error_code: "AI_API_ERROR",
    error_message: "Error al contactar con el motor de IA",
    data: null,
    _meta: {
      source: "NN_03_AI_Agent",
      timestamp: new Date().toISOString(),
      workflow_id: "NN_03"
    }
  }
}];
